using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        List<int> stock = new List<int>();

        stock.Add(12);
        stock.Add(4);
        stock.Add(18);
        stock.Add(2);
        stock.Add(9);

        CheckStock(stock);
    }

    static void CheckStock(List<int> stock)
    {
        for (int i = 0; i < stock.Count; i++)
        {
            if (stock[i] < 5)
            {
                Console.WriteLine("Low stock: " + stock[i]);
            }
            else
            {
                Console.WriteLine("Stock OK: " + stock[i]);
            }
        }
    }
}

