using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        List<int> temperatures = new List<int>();

        temperatures.Add(18);
        temperatures.Add(25);
        temperatures.Add(12);
        temperatures.Add(30);

        CheckTemperatures(temperatures);
    }

    static void CheckTemperatures(List<int> temperatures)
    {
        for (int i = 0; i < temperatures.Count; i++)
        {
            if (temperatures[i] >= 25)
            {
                Console.WriteLine("Warm day: " + temperatures[i]);
            }
            else
            {
                Console.WriteLine("Cool day: " + temperatures[i]);
            }
        }
    }
}
